// Trim to exactly 365 (we curated a few extras for safety; take the first 365).
const TRIMMED = VERSES.slice(0, 365);
if (TRIMMED.length !== 365) {
  console.error(`ERROR: expected 365 verses, got ${TRIMMED.length} (source has ${VERSES.length}).`);
  process.exit(1);
}

const escape = (s) => s.replace(/'/g, "''");
const fs = require('fs');
const path = require('path');

// Single-file flavor (kept for diffability).
const single = [
  '-- Idempotent: replaces the entire 365-day cycle.',
  'TRUNCATE TABLE public.daily_devotionals;',
  '',
  'INSERT INTO public.daily_devotionals (day_of_year, reference, verse) VALUES',
  ...TRIMMED.map(([ref, verse], i) => {
    const sep = i === TRIMMED.length - 1 ? ';' : ',';
    return `  (${i + 1}, '${escape(ref)}', '${escape(verse)}')${sep}`;
  }),
];
fs.writeFileSync(path.join(__dirname, 'seed-devotionals.sql'), single.join('\n') + '\n');

// Chunked flavor for application via MCP execute_sql (smaller payloads).
const CHUNK = 100;
const chunks = [];
for (let i = 0; i < TRIMMED.length; i += CHUNK) {
  const slice = TRIMMED.slice(i, i + CHUNK);
  const isFirst = i === 0;
  const head = [];
  if (isFirst) head.push('TRUNCATE TABLE public.daily_devotionals;');
  head.push('INSERT INTO public.daily_devotionals (day_of_year, reference, verse) VALUES');
  const rows = slice.map(([ref, verse], j) => {
    const idx = i + j + 1;
    const sep = j === slice.length - 1 ? ';' : ',';
    return `  (${idx}, '${escape(ref)}', '${escape(verse)}')${sep}`;
  });
  chunks.push([...head, ...rows].join('\n'));
}
fs.writeFileSync(path.join(__dirname, 'seed-devotionals.chunks.json'), JSON.stringify(chunks, null, 2));

console.log(`Generated SQL with ${TRIMMED.length} entries in ${chunks.length} chunks.`);
